#include <string>
#include <regex>
#include <fstream>
#include <sstream>
#include "markdown.hpp" // Include the markdown library

std::string markdownToHtml(const std::string& markdownText)
{
    // First, convert the markdown text to html
    std::string htmlText;
    markdown::to_html(markdownText, htmlText);

    // Next, replace any newlines with <br> tags
    htmlText = htmlText.replace(std::regex("\\n"), "<br>");

    // Finally, return the html text
    return htmlText;
}
