function checkPrimes(arr) {
  for (let i = 0; i < arr.length; i++) {
    const num = arr[i];
    if (isPrime(num)) {
      console.log(num);
      return;
    }
  }
  console.log("No prime numbers found.");
}

function isPrime(num) {
  if (num <= 1) return false;
  for (let i = 2; i <= num / 2; i++) {
    if (num % i === 0) return false;
  }
  return true;
}
```
